template:
// --- PARETO ANALYSIS ({{dimensionField}} by {{measureField}}) ---
[Temp_Pareto_Prep]:
LOAD [{{keyField}}], [{{measureField}}] RESIDENT [{{factTable}}];
LEFT JOIN ([Temp_Pareto_Prep])
LOAD [{{keyField}}], [{{dimensionField}}] RESIDENT [{{linkTable}}];

[Temp_Pareto_Agg]:
LOAD [{{dimensionField}}], Sum([{{measureField}}]) AS _SumMeasure RESIDENT [Temp_Pareto_Prep] GROUP BY [{{dimensionField}}];
DROP TABLE [Temp_Pareto_Prep];

[Temp_Pareto_Total]: LOAD Sum(_SumMeasure) AS _Total RESIDENT [Temp_Pareto_Agg];
LET vParetoTotal = Peek('_Total', 0, 'Temp_Pareto_Total');
DROP TABLE [Temp_Pareto_Total];

[Temp_Pareto_Sorted]:
NOCONCATENATE
LOAD [{{dimensionField}}], [_SumMeasure] RESIDENT [Temp_Pareto_Agg] ORDER BY [_SumMeasure] DESC;
DROP TABLE [Temp_Pareto_Agg];

[Pareto_{{dimensionField}}]:
LOAD
    [{{dimensionField}}],
    If(RangeSum([_SumMeasure], Peek('_AccMeasure')) / $(vParetoTotal) <= 0.8, Dual('Top 80%', 1), Dual('Bottom 20%', 0)) AS [{{dimensionField}}_Pareto_Flag],
    RangeSum([_SumMeasure], Peek('_AccMeasure')) AS _AccMeasure
RESIDENT [Temp_Pareto_Sorted];

DROP TABLE [Temp_Pareto_Sorted];
DROP FIELD [_AccMeasure] FROM [Pareto_{{dimensionField}}];

// --- DUAL FLAG INJECTION ---
[Temp_Dual_{{fieldName}}]:
LOAD *, Dual([{{fieldName}}], Match([{{fieldName}}], {{mappingPairs}})) AS [{{fieldName}}_Dual]
RESIDENT [{{targetTable}}];
DROP TABLE [{{targetTable}}];
RENAME TABLE [Temp_Dual_{{fieldName}}] TO [{{targetTable}}];
